import{c as e,Q as d,j as o,m as r}from"./chunks/framework.DjQs07CJ.js";const p=JSON.parse('{"title":"Vocabulary concepts","description":"","frontmatter":{"title":"Vocabulary concepts","outline":[2,3]},"headers":[],"relativePath":"reference/vocabulary.md","filePath":"reference/vocabulary.md","lastUpdated":1779171375000}'),a={name:"reference/vocabulary.md"};function c(n,t,i,s,l,u){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="nlpm-domain-vocabulary" tabindex="-1">NLPM Domain Vocabulary <a class="header-anchor" href="#nlpm-domain-vocabulary" aria-label="Permalink to &quot;NLPM Domain Vocabulary&quot;">​</a></h1><p>Canonical noun and verb registry across NLPM&#39;s two scopes (internal and auditor), plus the bright-line evaluation cluster and the deferred-vs-rejected split per the P6 precedence order.</p><h2 id="vocab-how-this-registry-is-built" tabindex="-1">How this registry is built <a class="header-anchor" href="#vocab-how-this-registry-is-built" aria-label="Permalink to &quot;How this registry is built {#vocab-how-this-registry-is-built}&quot;">​</a></h2><p>Every term listed below has <strong>literary warrant</strong> — it appears in at least one NLPM artifact today, captured by <code>analysis/scripts/extract-vocabulary.py</code>. Re-run that script after adding or renaming artifacts; the freshest output lives at <code>analysis/vocabulary-extract/summary.md</code>. New terms enter the registry only after one of the four warrant types from <code>analysis/vocabulary-design-principles.md</code> (P6) is satisfied — literary warrant alone is the entry bar for terms already in use; new coinages need user, structural, or domain warrant.</p><hr><h2 id="vocab-two-scopes-p1" tabindex="-1">Two scopes (P1) <a class="header-anchor" href="#vocab-two-scopes-p1" aria-label="Permalink to &quot;Two scopes (P1) {#vocab-two-scopes-p1}&quot;">​</a></h2><p>NLPM has two declared scopes. A homonym across them is a <strong>boundary</strong>, not a collision.</p><table tabindex="0"><thead><tr><th>Scope</th><th>Lives in</th><th>What it operates on</th></tr></thead><tbody><tr><td><strong>internal</strong></td><td><code>commands/</code>, <code>agents/</code>, <code>skills/</code>, <code>bin/</code>, <code>scripts/</code>, project CLAUDE.md</td><td>NLPM&#39;s own behavior — scoring, checking, fixing, testing, listing, trending NL artifacts in the current project.</td></tr><tr><td><strong>auditor</strong></td><td><code>.github/workflows/auditor-*.yml</code>, <code>auditor/</code></td><td>The self-evolution pipeline that audits external repos, opens contribution PRs, tracks outcomes, refines rules.</td></tr></tbody></table><p>A verb that appears in both scopes (<code>scan</code>, <code>test</code>, <code>discover</code>) carries the same identity criterion in both — these are sanctioned homonyms. A verb that appears in only one scope (<code>audit</code>, <code>contribute</code>, <code>track</code> in auditor; <code>score</code>, <code>check</code>, <code>fix</code>, <code>ls</code>, <code>trend</code>, <code>init</code> in internal) is scope-bound; using it in the other scope requires either renaming or declaring a second scope-specific definition.</p><hr><h2 id="vocab-verbs" tabindex="-1">Verbs <a class="header-anchor" href="#vocab-verbs" aria-label="Permalink to &quot;Verbs {#vocab-verbs}&quot;">​</a></h2><h3 id="internal-scope-nlpm-commands" tabindex="-1">Internal scope (NLPM commands) <a class="header-anchor" href="#internal-scope-nlpm-commands" aria-label="Permalink to &quot;Internal scope (NLPM commands)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Canonical verb</th><th>Output</th><th>Judgment?</th><th>Examples in corpus</th></tr></thead><tbody><tr><td><code>score</code></td><td>number + penalty list</td><td>no (deterministic)</td><td><code>commands/score.md</code>, <code>agents/scorer.md</code></td></tr><tr><td><code>check</code></td><td>consistency violation list</td><td>no (deterministic)</td><td><code>commands/check.md</code>, <code>agents/checker.md</code></td></tr><tr><td><code>test</code></td><td>pass/fail against named specs</td><td>no (deterministic)</td><td><code>commands/test.md</code>, <code>agents/tester.md</code></td></tr><tr><td><code>scan</code></td><td>pattern-match findings against a signature database</td><td>no (deterministic)</td><td><code>commands/security-scan.md</code>, <code>agents/vague-scanner.md</code>, <code>agents/security-scanner.md</code></td></tr><tr><td><code>fix</code></td><td>mutated artifact</td><td>no (mechanical)</td><td><code>commands/fix.md</code></td></tr><tr><td><code>ls</code></td><td>inventory of artifacts</td><td>no</td><td><code>commands/ls.md</code>, <code>agents/scanner.md</code></td></tr><tr><td><code>trend</code></td><td>history report</td><td>no</td><td><code>commands/trend.md</code></td></tr><tr><td><code>init</code></td><td>config file</td><td>no</td><td><code>commands/init.md</code></td></tr></tbody></table><p><strong>Deprecated synonyms (do not use in internal scope):</strong></p><ul><li><code>lint</code>, <code>validate</code> → use <code>check</code> (structural) or <code>score</code> (quality)</li><li><code>find</code>, <code>search</code>, <code>list</code> → use <code>ls</code></li><li><code>analyze</code> → use <code>score</code> (if quantitative) or pick a more specific verb</li><li><code>audit</code> → not in internal scope; live in auditor scope only</li></ul><h3 id="auditor-scope-github-workflows-auditor-yml-auditor-scripts" tabindex="-1">Auditor scope (<code>.github/workflows/auditor-*.yml</code>, <code>auditor/scripts/</code>) <a class="header-anchor" href="#auditor-scope-github-workflows-auditor-yml-auditor-scripts" aria-label="Permalink to &quot;Auditor scope (`.github/workflows/auditor-*.yml`, `auditor/scripts/`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Canonical verb</th><th>Output</th><th>Judgment?</th><th>Examples in corpus</th></tr></thead><tbody><tr><td><code>discover</code></td><td>candidate-repo list</td><td>no</td><td><code>auditor-discover.yml</code></td></tr><tr><td><code>audit</code></td><td>composite quality + security report</td><td><strong>yes</strong></td><td><code>auditor-audit.yml</code></td></tr><tr><td><code>contribute</code></td><td>PR(s) to target repo</td><td>no</td><td><code>auditor-contribute.yml</code></td></tr><tr><td><code>track</code></td><td>outcome events appended to <code>events.jsonl</code></td><td>no</td><td><code>auditor-track.yml</code></td></tr><tr><td><code>classify</code></td><td>categorical label on a PR comment</td><td>no (model-deterministic)</td><td><code>auditor-classify.yml</code></td></tr><tr><td><code>refine</code></td><td>rule-edit PR (human-gated)</td><td>no (LLM-generated, human-merged)</td><td><code>auditor-refine-rules.yml</code></td></tr><tr><td><code>cite</code></td><td>citation-edit PR (human-gated)</td><td>no</td><td><code>auditor-cite-exemplars.yml</code>, <code>propose-rule-citations.py</code></td></tr><tr><td><code>diff</code></td><td>finding-by-finding comparison</td><td>no</td><td><code>diff-findings.py</code>, <code>auditor-docs-diff.yml</code></td></tr><tr><td><code>report</code></td><td>rolled-up summary at a cadence</td><td>no</td><td><code>auditor-daily-report.yml</code>, <code>generate-daily-report.py</code></td></tr><tr><td><code>review</code></td><td>rule-review issue body (human reads, decides)</td><td><strong>yes</strong> (human)</td><td><code>auditor-rule-review.yml</code>, <code>generate-rule-review-body.py</code></td></tr><tr><td><code>propose</code></td><td>a draft for human approval</td><td>no</td><td><code>propose-rule-citations.py</code></td></tr><tr><td><code>validate</code></td><td>yes/no on a structural rule</td><td>no</td><td><code>validate-feedback.sh</code>, <code>validate-rule-ids.py</code></td></tr></tbody></table><blockquote><p><strong>Sibling-granularity note (P1):</strong> <code>report</code> is broader than its peers (<code>classify</code>, <code>refine</code>, <code>cite</code>, <code>diff</code>). The auditor&#39;s noun-named workflow convention absorbs this — workflows that produce reports are noun-named after the output (<code>auditor-daily-report</code>, <code>auditor-rule-review</code>), and the verb <code>report</code> is the generic act behind that family. Documented inconsistency, not a P1 violation; flagged here so future additions don&#39;t replicate the pattern without intent.</p></blockquote><p><strong>Cross-scope homonyms (same meaning in both scopes):</strong></p><ul><li><code>scan</code> — pattern-match against a signature database (used by <code>security-scan</code> command and <code>scan-suppressions.py</code>)</li><li><code>test</code> — pass/fail against named specs (used by <code>/nlpm:test</code> and <code>auditor-integration-test.yml</code>)</li><li><code>discover</code> — produce a candidate list (<code>/nlpm:ls</code> description text and <code>auditor-discover.yml</code>)</li></ul><h3 id="verbs-proposed-but-not-entered" tabindex="-1">Verbs proposed but not entered <a class="header-anchor" href="#verbs-proposed-but-not-entered" aria-label="Permalink to &quot;Verbs proposed but not entered&quot;">​</a></h3><p>Per the precedence order in <code>analysis/vocabulary-design-principles.md</code> (P6 last; warrant is an entry check, not a veto), proposed terms split into two lists.</p><p><strong>Deferred (P2–P5 satisfied; awaiting warrant):</strong></p><table tabindex="0"><thead><tr><th>Proposed verb</th><th>Closure gap or judgment named</th><th>Warrant needed</th></tr></thead><tbody><tr><td><code>triage</code></td><td>Finding-disposition (P4 closure: <code>finding</code> has no consumer verb)</td><td>User warrant — practitioner reaches for the term unprompted</td></tr><tr><td><code>review</code> (internal scope)</td><td>Human-in-the-loop reading, sanctioned cross-scope homonym with auditor <code>review</code></td><td>User warrant — practitioner names a review act in internal artifacts</td></tr><tr><td><code>rationalize</code></td><td>Vocabulary curation (P5: act of picking canonical from extracted frequencies has no name)</td><td>User warrant — practitioner names the curation act</td></tr></tbody></table><p>Deferred terms are documented but not yet canonical. R51 does <strong>not</strong> flag them as deprecated — they are nameless gaps, not synonyms.</p><p><strong>Rejected by higher principle (no entry possible regardless of warrant):</strong></p><table tabindex="0"><thead><tr><th>Proposed verb</th><th>Blocking principle</th><th>Reason</th></tr></thead><tbody><tr><td><code>audit</code> (internal scope)</td><td>P1</td><td>Merge test fails — <code>score</code>+<code>check</code> already cover internal-scope evaluation</td></tr><tr><td><code>lint</code> (internal scope)</td><td>P1</td><td>Synonym of <code>check</code>; same identity criterion</td></tr><tr><td><code>validate</code> (internal scope)</td><td>P1</td><td>Collapses to <code>check</code> in internal scope (canonical in auditor scope)</td></tr><tr><td><code>analyze</code> (internal scope)</td><td>P1</td><td>Synonym of <code>score</code>; quantitative evaluation</td></tr></tbody></table><hr><h2 id="vocab-nouns" tabindex="-1">Nouns <a class="header-anchor" href="#vocab-nouns" aria-label="Permalink to &quot;Nouns {#vocab-nouns}&quot;">​</a></h2><h3 id="artifact-class-nouns-rigid-survive-state-changes" tabindex="-1">Artifact-class nouns (rigid; survive state changes) <a class="header-anchor" href="#artifact-class-nouns-rigid-survive-state-changes" aria-label="Permalink to &quot;Artifact-class nouns (rigid; survive state changes)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Canonical noun</th><th>What it is</th><th>Examples</th></tr></thead><tbody><tr><td><code>artifact</code></td><td>any NL programming file Claude Code consumes</td><td>umbrella term</td></tr><tr><td><code>command</code></td><td><code>commands/*.md</code>, invoked via <code>/&lt;plugin&gt;:&lt;command&gt;</code></td><td><code>commands/score.md</code></td></tr><tr><td><code>agent</code></td><td><code>agents/*.md</code>, invoked via Task tool with <code>subagent_type</code></td><td><code>agents/scorer.md</code></td></tr><tr><td><code>skill</code></td><td><code>skills/&lt;plugin&gt;/&lt;name&gt;/SKILL.md</code>, auto-loaded by description match</td><td><code>skills/nlpm/rules/SKILL.md</code></td></tr><tr><td><code>rule</code></td><td>a numbered item (R01–R50) inside the rules skill</td><td>inside <code>skills/nlpm/rules/SKILL.md</code></td></tr><tr><td><code>hook</code></td><td>shell script wired via <code>hooks.json</code></td><td><code>hooks/hooks.json</code></td></tr><tr><td><code>manifest</code></td><td><code>plugin.json</code> or <code>marketplace.json</code></td><td><code>.claude-plugin/plugin.json</code></td></tr><tr><td><code>frontmatter</code></td><td>YAML block delimited by <code>---</code> at the top of a Markdown file</td><td>every command, agent, skill</td></tr></tbody></table><h3 id="implementation-role-nouns-p2-p3-—-agent-names-ride-alongside-command-verbs" tabindex="-1">Implementation-role nouns (P2/P3 — agent names ride alongside command verbs) <a class="header-anchor" href="#implementation-role-nouns-p2-p3-—-agent-names-ride-alongside-command-verbs" aria-label="Permalink to &quot;Implementation-role nouns (P2/P3 — agent names ride alongside command verbs)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role-noun</th><th>Paired verb</th><th>File</th></tr></thead><tbody><tr><td><code>scanner</code></td><td><code>ls</code></td><td><code>agents/scanner.md</code></td></tr><tr><td><code>scorer</code></td><td><code>score</code></td><td><code>agents/scorer.md</code></td></tr><tr><td><code>checker</code></td><td><code>check</code></td><td><code>agents/checker.md</code></td></tr><tr><td><code>tester</code></td><td><code>test</code></td><td><code>agents/tester.md</code></td></tr><tr><td><code>vague-scanner</code></td><td><code>score</code> (sub-step)</td><td><code>agents/vague-scanner.md</code></td></tr><tr><td><code>security-scanner</code></td><td><code>scan</code></td><td><code>agents/security-scanner.md</code></td></tr></tbody></table><p>These are <strong>not top-level verbs in their own right</strong> (P3). They are role-names for sub-step agents. Treat them as nouns naming the worker, not as operations on artifacts.</p><h3 id="output-class-nouns-produced-by-verbs" tabindex="-1">Output-class nouns (produced by verbs) <a class="header-anchor" href="#output-class-nouns-produced-by-verbs" aria-label="Permalink to &quot;Output-class nouns (produced by verbs)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Noun</th><th>Produced by</th><th>Notes</th></tr></thead><tbody><tr><td><code>score</code></td><td><code>score</code> verb</td><td>number 0–100 + penalty breakdown</td></tr><tr><td><code>finding</code></td><td><code>score</code>, <code>check</code>, <code>scan</code></td><td>one problem detected; carries a fingerprint in auditor scope</td></tr><tr><td><code>violation</code></td><td><code>check</code></td><td>a finding specifically from cross-reference checking</td></tr><tr><td><code>penalty</code></td><td><code>score</code></td><td>the points subtracted by a single finding</td></tr><tr><td><code>snapshot</code></td><td><code>score</code>, <code>trend</code></td><td>a point-in-time record appended to <code>.claude/nlpm-history.json</code></td></tr><tr><td><code>inventory</code></td><td><code>ls</code></td><td>the list of artifacts discovered in a path</td></tr><tr><td><code>report</code></td><td><code>audit</code>, <code>report</code>, <code>trend</code></td><td>a roll-up document</td></tr><tr><td><code>spec</code></td><td><code>test</code></td><td>a <code>.nlpm-test/*.spec.md</code> file defining expected behavior</td></tr></tbody></table><h3 id="auditor-scope-nouns-only-meaningful-inside-auditor" tabindex="-1">Auditor-scope nouns (only meaningful inside <code>auditor/</code>) <a class="header-anchor" href="#auditor-scope-nouns-only-meaningful-inside-auditor" aria-label="Permalink to &quot;Auditor-scope nouns (only meaningful inside `auditor/`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Noun</th><th>What it is</th><th>File evidence</th></tr></thead><tbody><tr><td><code>case-study</code></td><td>post-merge article comparing original audit to HEAD</td><td><code>auditor/audits/&lt;slug&gt;.re-audit.md</code></td></tr><tr><td><code>exemplar</code></td><td>teaching artifact from a high-scoring audit</td><td><code>auditor/exemplars/&lt;slug&gt;.md</code></td></tr><tr><td><code>fingerprint</code></td><td>content-hash identity of a finding across re-runs</td><td><code>compute-fingerprint.sh</code></td></tr><tr><td><code>event</code></td><td>one append-only record in <code>events.jsonl</code></td><td><code>auditor/logs/events.jsonl</code></td></tr><tr><td><code>disagreement</code></td><td>self/maintainer dispute over a finding</td><td><code>auditor/disagreements.jsonl</code></td></tr><tr><td><code>registry</code></td><td>the tracked-repo database</td><td><code>auditor/registry/repos.json</code></td></tr><tr><td><code>disposition</code></td><td>a finding&#39;s lifecycle status</td><td>enum values inside <code>events.jsonl</code></td></tr><tr><td><code>policy gate</code></td><td>a pre-PR check (no-external-PRs, CLA, pushback)</td><td><code>auditor-contribute.yml</code></td></tr></tbody></table><hr><h2 id="vocab-the-bright-line-table-p1-p5" tabindex="-1">The bright-line table (P1, P5) <a class="header-anchor" href="#vocab-the-bright-line-table-p1-p5" aria-label="Permalink to &quot;The bright-line table (P1, P5) {#vocab-the-bright-line-table-p1-p5}&quot;">​</a></h2><p>When the evaluation cluster overlaps in practice, use this table to disambiguate:</p><table tabindex="0"><thead><tr><th>Verb</th><th>Scope</th><th>Deterministic?</th><th>Judgment?</th><th>Output</th><th>Use when</th></tr></thead><tbody><tr><td><code>score</code></td><td>internal</td><td>yes</td><td>no</td><td>number + penalty list</td><td>quantifying quality with a rubric</td></tr><tr><td><code>check</code></td><td>internal</td><td>yes</td><td>no</td><td>violation list</td><td>verifying cross-references and structural consistency</td></tr><tr><td><code>test</code></td><td>both</td><td>yes</td><td>no</td><td>pass/fail</td><td>comparing actual behavior against a named spec</td></tr><tr><td><code>scan</code></td><td>both</td><td>yes</td><td>no</td><td>findings against signatures</td><td>pattern-matching for a known class of problems</td></tr><tr><td><code>audit</code></td><td>auditor</td><td>partly</td><td><strong>yes</strong></td><td>composite report</td><td>full quality assessment that combines score + scan + judgment</td></tr><tr><td><code>review</code></td><td>auditor</td><td>no</td><td><strong>yes (human)</strong></td><td>comment trail</td><td>a human reads and forms an opinion</td></tr></tbody></table><p>Two verbs share a scope and an identity criterion ⇒ one must be retired or scope-split. Two verbs share an identity criterion across scopes ⇒ that is a sanctioned homonym (declare it in this table).</p><hr><h2 id="vocab-how-to-extend-this-registry" tabindex="-1">How to extend this registry <a class="header-anchor" href="#vocab-how-to-extend-this-registry" aria-label="Permalink to &quot;How to extend this registry {#vocab-how-to-extend-this-registry}&quot;">​</a></h2><ol><li><strong>Add a term only if it has warrant.</strong> The four warrant types come from <code>analysis/vocabulary-design-principles.md</code> P6: literary, user, structural, domain. Literary warrant is automatic via the extraction script — if the script picks the term up, it qualifies.</li><li><strong>Re-run the extraction script.</strong> <code>python3 analysis/scripts/extract-vocabulary.py</code> writes <code>analysis/vocabulary-extract/summary.md</code>. New terms appear there.</li><li><strong>Slot the term.</strong> Add a row to the right table above (internal verb / auditor verb / artifact-class noun / role-noun / output-class noun / auditor-scope noun).</li><li><strong>Cite the file evidence.</strong> Every row has an &quot;examples&quot; or &quot;file evidence&quot; column. Cite at least one path.</li><li><strong>If retiring a synonym, list it under its canonical verb&#39;s &quot;deprecated synonyms&quot; line.</strong> Do not silently drop terms; deprecation is itself a vocabulary act and needs to be visible.</li></ol><hr><h2 id="vocab-deferred-work-documented-not-yet-executed" tabindex="-1">Deferred work (documented, not yet executed) <a class="header-anchor" href="#vocab-deferred-work-documented-not-yet-executed" aria-label="Permalink to &quot;Deferred work (documented, not yet executed) {#vocab-deferred-work-documented-not-yet-executed}&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Why deferred</th><th>What unblocks it</th></tr></thead><tbody><tr><td>Per-rule warrant tags on R01–R50</td><td>Requires reading every rule + judging which warrant it earns its place by. User warrant data lives in <code>rule-health.py</code> outputs.</td><td>A separate <code>auditor-refine-rules</code> follow-up pass that combines rule-health data with this principle set.</td></tr><tr><td>Adding <code>triage</code> as a <code>/nlpm:triage</code> command</td><td>P4 closure gap is real but <code>triage</code> has zero literary warrant today. User warrant is the missing evidence.</td><td>A practitioner reaching for the word unprompted in actual NLPM use.</td></tr><tr><td>Resolving the agent-name-vs-command-name shadowing (<code>scanner</code>/<code>ls</code>, <code>scorer</code>/<code>score</code>)</td><td>Already documented above as a class boundary; no rename proposed.</td><td>A confirmed case of practitioner confusion. None observed today.</td></tr><tr><td>(resolved 2026-05-19) Workflow filename convention</td><td>Declared as sanctioned split. See &quot;Auditor workflow filename convention&quot; below.</td><td>—</td></tr></tbody></table><hr><h2 id="vocab-auditor-workflow-filename-convention" tabindex="-1">Auditor workflow filename convention <a class="header-anchor" href="#vocab-auditor-workflow-filename-convention" aria-label="Permalink to &quot;Auditor workflow filename convention {#vocab-auditor-workflow-filename-convention}&quot;">​</a></h2><p><code>.github/workflows/auditor-*.yml</code> filenames follow a <strong>two-rule split</strong>, both sanctioned:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Use when</th><th>Examples</th></tr></thead><tbody><tr><td><code>auditor-&lt;verb&gt;</code></td><td>The workflow changes state (gates a transition, opens a PR, classifies, moves a finding through its lifecycle)</td><td><code>auditor-audit.yml</code>, <code>auditor-contribute.yml</code>, <code>auditor-track.yml</code>, <code>auditor-classify.yml</code>, <code>auditor-refine-rules.yml</code>, <code>auditor-cite-exemplars.yml</code>, <code>auditor-discover.yml</code></td></tr><tr><td><code>auditor-&lt;output-noun&gt;</code></td><td>The workflow&#39;s purpose is to produce a named artifact that downstream tooling consumes by name</td><td><code>auditor-case-study.yml</code>, <code>auditor-exemplar.yml</code>, <code>auditor-daily-report.yml</code>, <code>auditor-suppressions.yml</code>, <code>auditor-docs-diff.yml</code>, <code>auditor-rule-review.yml</code></td></tr></tbody></table><p>By P3, both patterns produce or gate, so both pass the top-level-verb test. The split is genuine: noun-named workflows are named after what they write, verb-named workflows after what they do.</p><p><strong>Outlier:</strong> <code>auditor-batch-processor.yml</code> is named after a process role, not a verb or an output noun. Rename candidate: <code>auditor-promote-batch</code>. Deferred — git history, badge, and external references make the rename costly, and the existing name has literary warrant.</p><hr><h2 id="vocab-scope-note" tabindex="-1">Scope note <a class="header-anchor" href="#vocab-scope-note" aria-label="Permalink to &quot;Scope note {#vocab-scope-note}&quot;">​</a></h2><p>This skill loads on requests to write, review, or name NLPM artifacts. For framework-level facts (hook event names, manifest field schemas, Claude Code naming conventions), see [[conventions]]. For the 50 quality rules (R01–R50), see [[rules]]. For penalty tables, see [[scoring]].</p>',58)])])}const m=e(a,[["render",c]]);export{p as __pageData,m as default};
